var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L5_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니.","JPN":"お母さん。","ENG":"Mother?","TWN":"媽媽？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저 하늘엔 별들이 왜 저렇게 많아요?","JPN":"空にはなんであんなに星がたくさんあるんですか？","ENG":"Why are there so many stars up in the sky?","TWN":"天上面，為什麼會有那麼多的星星？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"사람들의 소망이 저 하늘에 모이기 때문이란다.","JPN":"皆の願いがあの空に集まるからだよ。","ENG":"That's because people's wishes gather in the sky.","TWN":"因為呀，大家的願望都聚集在那片天空之中了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그 소망은 하늘에 박힌 별이 되어서 저렇게 반짝이는 거지.","JPN":"そしてその願いは空を飾る星になって、ああやって輝くの。","ENG":"And those wishes become twinkling stars.","TWN":"然後，那些願望就會變成嵌在天空當中的星星，一閃一閃地發著光芒。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"저 중에 제 별도 있을까요?","JPN":"あの中に、私の星もあるかな？","ENG":"Do you think my star is up there too?","TWN":"哇！在那中間會有我的星星嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼. 당연하지.","JPN":"もちろん。","ENG":"Yes, of course.","TWN":"當然了～"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 소망이 너무 커지면 말이야, 그 소망을 담고 있던 별이 톡 하고 빠져서 땅으로 떨어진단다.","JPN":"あとね、願いが大きくなると、願いを宿していた星がぽつりと地面に落ちてくるのよ。","ENG":"When a wish becomes too big, the star gets too heavy and falls down to the ground.","TWN":"而且如果願望變得很大很大，承載那個願望的星星就會啪地一聲掉到地上。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 떨어진 별은 그 사람을 찾아가서 소망을 실제로 이뤄준다고 해.","JPN":"そうやって落ちた星は、願いをかけた人のもとにやってきて願いを叶えてくれるんだって。","ENG":"It's said that a fallen star will go find its wish's owner and make it come true.","TWN":"那顆墜落的星星會找到許下願望的那個人，並實現他的願望。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"와아- 대단해.","JPN":"わあ～すごい。","ENG":"Wow! That's incredible.","TWN":"哇——真厲害！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니도 소원을 빌었어요? 별님이 떨어졌나요?","JPN":"お母さんもお願いしたんですか？　お星さまは落ちました？","ENG":"Did you make a wish too, Mother? Did yours fall down to earth?","TWN":"媽媽也許願了嗎？有星星掉下來了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"그러엄-","JPN":"そうだよ～","ENG":"Of course, it did.","TWN":"那樣啊——"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"내 별은 이미 오래 전에 떨어져서 소원을 이뤄줬거든.","JPN":"私の星はとっくに落ちて、願いを叶えてくれたの。","ENG":"My star fell a long time ago and made my wish come true.","TWN":"我的星星在很久之前就已經墜落下來，實現了我的願望。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그럼 그 소원이 무엇이었냐는 내 질문에…","JPN":"何を願ったのか尋ねると……","ENG":"And when I asked what that wish was...","TWN":"那時候，我問媽媽那個願望是什麼……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"어머니는 조용히 웃으며 날 안아줄 뿐이었다.","JPN":"お母さんはただ笑って、私を抱きしめてくれた。","ENG":"Mother silently smiled and hugged me.","TWN":"她只是靜靜地笑著抱住了我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"그때는 그 행동에 담긴 의미를 이해하지 못했다.","JPN":"あの時は、その行動の意味が分からなかった。","ENG":"At the time, I didn't understand what that meant.","TWN":"那時的我還無法理解這個動作背後的意義。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"그저 어머니의 품이 사랑스럽고 따스하다고만 생각했다.","JPN":"ただ、お母さんの腕の中が温かくて心地良かった。","ENG":"I just thought that it was warm and loving in Mother's embrace.","TWN":"只是覺得媽媽的懷抱既有愛又溫暖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"헉… 헉…!","JPN":"はあ……はあ……！","ENG":"*Huff* *Huff*","TWN":"哈…… 哈……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"별님의 빛이 향하는 곳으로… 무작정 쫓아간다.","JPN":"お星さまの光が指すほうへ……ただひたすら走って行く。","ENG":"I started running... toward where the star was twinkling.","TWN":"去星星指引的地方吧！向著那裡一直奔跑……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"하늘만 바라보며, 우거진 수풀 사이를 달린다.","JPN":"空を見つめながら、茂みの中を駆ける。","ENG":"With my eyes locked at the sky, I ran through the thicket.","TWN":"望著天空，在茂密的樹叢間不停追趕。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 저 빛이 있는 자리에 내가 원하는 대답이 있을지도 모른다는…","JPN":"もしかしたら、あの光の元に行けば、私の求める答えが得られるかもしれない……","ENG":"I thought to myself...","TWN":"我輕輕地對自己說著……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그런 막연한 생각을 하면서.","JPN":"漠然とした期待を抱いて。","ENG":"that the answer I was looking for could be where that light had fallen.","TWN":"也許在那裡，會有我想要的答案……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"하아… 하…","JPN":"はあ……はぁ……","ENG":"*Huff* *Huff*","TWN":"哈啊……哈……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"여긴…?","JPN":"ここは……？","ENG":"This place is...","TWN":"這裡是……？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"무덤이요?","JPN":"お墓？","ENG":"A graveyard?","TWN":"這就是墓地嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"응. 관리국의 용감한 동료들이 잠들어있는 곳이야.","JPN":"うん。管理局の勇敢な仲間たちがここに眠っているの。","ENG":"Yes. It is where the courageous comrades of the Administration are laid to rest.","TWN":"嗯。這裡是管理局勇敢的同伴們長眠的地方。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"우리 세계를 지키기 위해 목숨을 바친 영웅들의 안식처지.","JPN":"私たちの世界を守るために命を捧げた英雄たちの拠り所ね。","ENG":"This is the resting place for the heroes who have sacrificed their lives to protect our world.","TWN":"是為了保護我們世界而獻出生命的英雄們的安息之地。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 많은 안식처를… 어머니 혼자서 만든 건가요?","JPN":"こんなにたくさんのお墓を……お母さん1人で作ったんですか？","ENG":"There are so many... Did you make all of them, Mother?","TWN":"這麼多的墓碑……都是媽媽一個人建造的嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"나에겐 시간이 아주 많았거든.","JPN":"私には時間がとってもたくさんあったの。","ENG":"I had a lot of time on my hands.","TWN":"媽媽有很多的時間。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그들을 묻고 애도할 시간도, 그들과 함께 했던 지난 날을 추억 할 시간도 말이야.","JPN":"彼らを埋めて弔う時間も、彼らと共に過ごした時間を振り返る時間もね。","ENG":"Enough to bury and mourn them, and even reminisce about the times I had with them.","TWN":"足夠用來埋葬和哀悼他們，也足夠回憶與他們一起的日子。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"사람이 죽으면, 어떻게 돼요?","JPN":"人は、死んだらどうなるんですか？","ENG":"What happens to people when they die?","TWN":"媽媽，人死了會怎麼樣？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"영원한 잠에 빠진 채, 남겨진 사람들의 기억 속에서 살아가겠지.","JPN":"永遠の眠りについて、残された人々の記憶の中で生きていくんだよ。","ENG":"They fall into an eternal slumber, and live on in the memories of those left behind.","TWN":"他們會陷入永恆的沉睡，活在留下的人的記憶當中。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"다시 만나지 못한다는 건 슬픈 일이지만… 그저 슬프기만 한 건 아냐.","JPN":"2度と会えないのは悲しいことだけど……悲しいだけじゃない。","ENG":"It's sad that we won't be able to ever meet them again, but... sadness is not all of it.","TWN":"雖然再也見不到面是件悲傷的事……但這個不僅僅只關乎到悲傷。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"우린 마지막까지 최선을 다했으니까.","JPN":"私たちは最後まで最善を尽くしたから。","ENG":"Because we tried our best until the end.","TWN":"因為我們已經盡力到最後一刻了。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"우리가 선택한 운명이 언젠가 미래에 희망을 가져다줄 거라고… 그렇게 믿고 있으니까.","JPN":"私たちが選んだ運命が、いつかの未来に希望をもたらしてくれると……そう信じているから。","ENG":"Still believing that the fate we chose will bring hope to the future...","TWN":"我們選擇的命運，總有一天會給未來帶去希望……我們堅信著這一點。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"관리국은 지금도 그런 희망을 품고, 저 밤하늘 어딘가에서 미래를 위해 싸우고 있는 거란다.","JPN":"管理局は今もそんな希望を抱いて、あの夜空のどこかで未来のために戦っているんだよ。","ENG":"And the Administration still holds on to that hope, still fighting for the future, somewhere in the night sky.","TWN":"管理局現在應該也懷抱著這樣的希望，在那夜空中的某處為未來而戰鬥著。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 영웅들은 정말 대단하네요.","JPN":"管理局の英雄たちはすごいですね。","ENG":"The heroes of the Administration are really amazing.","TWN":"哇，管理局的英雄們真是了不起啊。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그치만 다들 노력했는데… 무덤에 잠든 분들만 그 미래를 못 본다고 생각하면 많이 아쉬울 것 같아요.","JPN":"でも一生懸命頑張ったのに……お墓に眠ってる人たちはその未来を見れないなんて……寂しいです。","ENG":"But after all their efforts... it's a shame that those resting in their graves won't be able to see that future.","TWN":"可是明明大家都努力了……一想到只有睡著的人們看不到那個未來，不會覺得很遺憾嗎？"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…그래. 하지만 적어도 무의미하진 않을 거야.","JPN":"……そうだね。でも無駄じゃなかった。","ENG":"...It is. But at least it won't be meaningless.","TWN":"……嗯，但至少不會毫無意義。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"우리가 미래에 남아서 전부 기억할 테니까.","JPN":"私たちが、未来ですべてを覚えているから。","ENG":"Because we will live on into the future and remember all of it.","TWN":"我們會活在未來，並記住這裡發生過的一切。"},"stage":{"bg":"SWORDGRAVE","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"오늘이 있기 전의 과거에, 그들의 희생이 있었다는 사실을 말이야.","JPN":"彼らの犠牲があったから、こうして今日を迎えられたんだよ。","ENG":"We'll remember the sacrifices they made in the past.","TWN":"我們會記得他們曾經做出過的犧牲。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"헥… 헤엑…!","JPN":"ぜえ、はあ……","ENG":"*Huff* *Huff*","TWN":"呼呼……呼……！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"드디어 따라잡았네, 이 녀석…!","JPN":"こいつ……やっと追いついた……！","ENG":"I finally caught up with you... Why you...!","TWN":"終於追上你了，這個傢伙……！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"네 덩굴을 빠져나오느라 내가 관절을 몇 번 꺾어야 했는지 알아?","JPN":"あなたのツタから抜け出すのに、何度関節を折ったと思う！？","ENG":"Do you know how many joints I had to snap to escape your vines?","TWN":"你知道我為甩開那些藤蔓，扭到多少次關節嗎！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 무기들은 전부… 관리국의…?","JPN":"この武器は全部……管理局の……？","ENG":"Those weapons... they're all the Administration's...?","TWN":"這些武器全都是……管理局的……？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하나 하나에 전부… 이름과 글귀가 새겨져 있어.","JPN":"武器1つ1つに……名前と文章が刻まれている。","ENG":"Each and every one of them... have names and words engraved on them.","TWN":"每一個上面……都刻有名字和事蹟。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 어머니 뱃속에 있을 때…","JPN":"私がお母さんのお腹にいた時……","ENG":"When I was in Mother's womb...","TWN":"這是我還在媽媽肚子裡的時候……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니가 돌아가신 관리국 영웅들을 추억하며 만든 묘지래요.","JPN":"お母さんが、亡くなった管理局の英雄たちを追悼するために作ったお墓です。","ENG":"Mother made all these tombs remembering the heroes of the Administration who passed away.","TWN":"媽媽為了紀念那些管理局犧牲的英雄們而建的墓地。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이걸 전부 만들려면… 적어도 제가 살아온 시간보다 훨씬 긴 시간이 필요했을 거예요.","JPN":"これを全部作るためには……少なくとも、私が生きてきた時間よりもっと長い時間がかかったことでしょう。","ENG":"It would've taken... much longer than my entire life to make them all.","TWN":"全部做完……至少需要比我活到現在還要長得多的時間。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 많은 묘지를… 파블린 혼자 만들었다고?","JPN":"こんなに沢山のお墓を……パブリン1人で？","ENG":"Pavlin made... all these gravestones by herself?","TWN":"這麼多墓碑……都是帕芙琳一個人建的嗎？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데요. 뱃속의 아이가 태어나는 데 걸리는 시간은 생일이 한 번 돌아오는 것보다 짧대요.","JPN":"でもね。お腹の子どもが生まれるまでの時間は、誕生日が巡ってくる時間よりも短いんですって。","ENG":"But you know. The time it takes for a baby to be born is shorter than waiting for one's birthday to come around.","TWN":"不過啊，肚子裡的孩子出生所花費的時間比過一次生日還要短呢。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이상하죠? 절 품은 어머니가 그렇게 오랜 시간 동안 혼자 지냈다는 게 말이예요.","JPN":"変ですよね？　私を身ごもったお母さんが、そんなに長い時間を1人で過ごしたなんて。","ENG":"Isn't that weird? It means that Mother spent all this time alone while she had me in her womb.","TWN":"奇怪吧？媽媽在懷著我的時候竟然獨自生活了那麼久。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"세상이 불바다가 됐을 때, 관리국이 나타나서 어머니를 구해줬어요.","JPN":"この世界が戦火に焼かれた時、管理局が現れてお母さんを助けてくれました。","ENG":"Mother told me that the Administration came and saved Mother when the world was in flames.","TWN":"當世界被點燃的時候，是管理局出現並救了媽媽。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그날 어머니는 가족을 전부 잃었고, 저랑 둘만 살아 남았대요.","JPN":"あの日お母さんは家族をみんな失って、私と2人だけが生き残ったそうです。","ENG":"That day, Mother lost all her family, and we were the only ones left.","TWN":"那天媽媽失去了所有的家人，只剩下我和她兩個人活了下來。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머닌 제가 태어날 미래를 위해 관리국과 함께 싸웠고…","JPN":"お母さんは私が生まれる未来のために管理局と共に戦い……","ENG":"Mother fought alongside the Administration for a future in which I would be born...","TWN":"媽媽為了我能夠出生的未來，與管理局一起作戰……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"모두의 노력 덕분에 지금까지 올 수 있었던 거래요.","JPN":"みんなの努力があったから、今まで生きて来られたと言っていました。","ENG":"We were able to come this far thanks to everyone's efforts.","TWN":"並且多虧了大家的努力，我們才能走到今天。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데…","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"관리국과 헤어지던 마지막 날의 기억에서, 어머니가 갑자기 이상한 말을 했어요.","JPN":"管理局の人とお別れした最後の日、記憶の中でお母さんは変なことを言ったんです。","ENG":"In the memory of the day she parted ways with the Administration, Mother said something strange.","TWN":"在與管理局告別的最後一天，媽媽突然說了一些奇怪的話。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 태어나지 못할 거래요.","JPN":"私は生まれないって。","ENG":"That I wouldn't be born.","TWN":"她說……我本不該出生的。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"세계가 멸망한 시점에서 시간의 흐름은 더 이상 존재하지 않아.","JPN":"世界が滅びた時点で、時間の流れは存在しなくなる。","ENG":"From the moment a world is destroyed, the flow of time no longer exists.","TWN":"因為在世界毀滅的那一刻，時間的流逝便不復存在了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"시간이 사라진단 건, 네가 태어날 미래도 없다는 뜻이지.","JPN":"時間がなくなるということは、あなたが生まれる未来もなくなるってことだよ。","ENG":"And without time, your future of being born is also non-existent.","TWN":"而時間消失，就就表示你沒有誕生的未來。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"말도 안돼요…!","JPN":"でもそんなこと……！","ENG":"That makes no sense...!","TWN":"那樣不可能……！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리도 제가 보이잖아요! 제 손의 온기가 느껴지지 않나요?","JPN":"パリーにも私が見えるでしょう？　手のぬくもりがわかりませんか？","ENG":"I'm right here, Parry! Can't you feel the warmth of my hand?","TWN":"悖悖，我就在你面前啊！難道你感覺不到我手上的溫暖嗎？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"전 여기 존재해요! 어머니와의 행복했던 과거도 진짜예요!","JPN":"私はここにいます！　お母さんとの幸せな過去も本物です！","ENG":"I exist right here! And all my happy memories with Mother are real!","TWN":"我在這裡啊！和媽媽幸福的過去也是真的！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"가짜 같은 게 아니라고요!","JPN":"偽物なんかじゃありません！","ENG":"They aren't fake!","TWN":"這些怎麼會是假的呢！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데…","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니는 저한테 미안하다고 했어요.","JPN":"お母さんは、私にごめんなさいと言ったんです。","ENG":"Mother said she was sorry to me.","TWN":"媽媽對我說著對不起。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"꼭… 영원히 못 볼 것처럼 슬퍼하고 있었어요.","JPN":"まるで……永遠に会えないとでもいうように悲しんでました。","ENG":"She was sad... like we'd never see each other.","TWN":"就像……永遠見不到了一樣悲傷。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 정원은 멸망을 눈앞에 둔 세계로부터 유일하게 격리된 장소다.","JPN":"この庭園は、滅亡直前の世界から唯一隔離されている場所。","ENG":"This garden is the only place that is isolated from a world on the brink of destruction.","TWN":"這座花園是唯一一個與瀕臨毀滅的世界所隔離的地方。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린이 종말을 앞둔 세상에 남은 모든 가능성을 끌어모아 만든 작은 세계지.","JPN":"パブリンが終末を迎える前、世界に残ったすべての可能性をかき集めて作った小さな世界だよ。","ENG":"Pavlin made this little world by gathering all the possibilities that were left.","TWN":"帕芙琳在末日來臨的世界中，彙聚了所有剩餘的可能性，創造了這個小小的世界。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"가능성은 변화에 의해 소실되기 마련이지만, 그곳의 시간은 언제나 멈춰있기 때문에 영원한 안전이 보장되는 곳이었어.","JPN":"可能性は変化によって失われるものだけど、この場所は常に時間が止まっているから永遠の安全が保証された。","ENG":"Possibilities are bound to be lost due to change, but because time stands still there, it was a place where eternal safety was guaranteed.","TWN":"可能性總會因為變化而消失，但在這裡，時間是永遠停滯的，所以是一個永遠安全的地方。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 그 멈춘 시간의 세계에서 우리를 기다리기로 했던 거고.","JPN":"パブリンはその、時間の止まった世界で私たちを待つことにしたんだ。","ENG":"Pavlin said that she'd wait for us in a world where time froze.","TWN":"帕芙琳說她會在這個停滯的時間裡等待我們。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그건… 기약 없이 아주 오랜 기다림이었을 거야.","JPN":"多分……気が遠くなるほどの時間だっただろうね。","ENG":"That... must have been a long wait, with no guarantee.","TWN":"那是個……無盡的漫長等待。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"아무런 변화도 일어나지 않는 새장 속에 갇혀…","JPN":"何の変化もない鳥かごに閉じ込められて……","ENG":"It was her last mission...","TWN":"被困在沒有任何變化的牢籠中……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"어쩌면 영원히 찾아오지 않을지도 모를 누군가를 하염없이 기다리며 스승의 기억을 지키는 게… 그녀의 마지막 사명이었어.","JPN":"もしかしたら永遠にやってこないかもしれない誰かをひたすら待ち続け、師匠の記憶を守ること……それが彼女の最後の使命だった。","ENG":"to protect her master's memory while waiting forever for someone who may never come... while trapped in a bird cage where nothing changes.","TWN":"等待也許永遠也不會到來的某個人，守護著她師父的記憶……作為她最後的使命。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"왜 어머니는… 함께 떠날 수 없었던 거죠?","JPN":"どうしてお母さんは……管理局と一緒に行けなかったんですか？","ENG":"Why couldn't... Mother leave with you?","TWN":"為什麼媽媽……不能一起離開呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 대적자야. 그 운명은 처음부터 자신의 세계와 탯줄처럼 묶여 있지.","JPN":"パブリンは敵対者だよ。その運命はまるで臍の緒みたいに、最初から自分の世界と繋がっている。","ENG":"Pavlin was the Antagonist. Her fate was bound to the world since birth.","TWN":"帕芙琳是敵對者。她的命運從一開始就像臍帶一樣與世界緊緊相連了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"이 정원은 종말을 앞둔 파블린의 운명을 멈추게 할 뿐.","JPN":"この庭園は終末を控えたパブリンの運命を止めるだけ。","ENG":"And this garden only stops Pavlin's fate from coming to an end.","TWN":"這座花園只是暫時阻止了她即將到來的命運。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"우리가 언젠가 기적처럼 돌아온다 해도, 함께 떠난다는 건 불가능한 일이었어.","JPN":"いつか奇跡的に私たちが帰ってきたとしても、一緒にここを離れることは不可能だった。","ENG":"Even if we miraculously returned one day, it still would be impossible for her to leave with us.","TWN":"即使我們有一天奇蹟般地回來了，也不可能帶她一起離開。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼 어머니는… 평생 시간조차 흐르지 않는 곳에서 살아가야 했다고요?","JPN":"じゃあお母さんは……その一生を時間の流れのないこの場所で過ごすしかなかったのですか？","ENG":"Then Mother... had to live a lifetime in a place where time didn't even exist?","TWN":"那麼媽媽……要在這個連時間都不會流逝的地方生活一輩子嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"태어날 미래가 존재하지 않는 뱃속의 아이와 함께 죽음조차 없는 영원을 살아간다는 건…","JPN":"生まれる未来を迎えられないお腹の子どもと一緒に、死すらない永遠を生きる……","ENG":"To live an eternity without death with her unborn child who has no future...","TWN":"和腹中沒有未來的孩子一起，度過連死亡都不存在的永恆……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"감히 상상컨대, 죽음보다 가혹한 경험이었을 거야.","JPN":"想像もできないぐらい過酷な経験だっただろうね。","ENG":"I can't even fathom how much worse that would be than death.","TWN":"我敢想像，那一定是比死亡更為殘酷的經歷。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그렇게 오늘과 다름없는 오늘만이 반복되던… 그런 어느 날이었겠지.","JPN":"そうやって何も変わらない毎日が繰り返されていたある日……","ENG":"It would've been... another loop of /\\"today/\\".","TWN":"就這樣，一天天重複著昨日的生活，直到那麼一天……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"모든 것이 멈춰있던 그 작은 세계에 변화가 일어나기 시작했어.","JPN":"すべてが止まっていた小さな世界に変化が起きた。","ENG":"Then, a change started to happen in this small world where time has stopped.","TWN":"在一切都停滯的小小的世界裡，變化開始發生了。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"차가운 황무지 뿐이던 곳에 풀이 자라고, 꽃이 피어나.","JPN":"荒んだ更地に草が生え、花が咲く。","ENG":"Grass grew, and flowers bloomed in the cold barren lands.","TWN":"在曾經冰冷的荒原上，草木開始生長，花朵開始綻放。"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"시간의 흐름과 함께 모든 것들의 운명이 흐르기 시작했어.","JPN":"時間の流れと共に、すべての存在の運命が動き出した。","ENG":"With the flow of time, the fate of all things began to move.","TWN":"隨著時間的流逝，一切事物的命運開始流轉。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 영원한 기다림을 깨고, 변화를 선택한 거야.","JPN":"パブリンは永遠に待つことを止め、変化を選んだの。","ENG":"Pavlin broke the eternal wait, and chose change.","TWN":"帕芙琳打破了永恆的等待，選擇了改變。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그렇게 미래라곤 존재하지 않던 그녀의 세계에, 한 아이가 태어난 거지.","JPN":"そして未来というものが存在しなかった彼女の世界に、1人の子どもが生まれた。","ENG":"Thus, a child was born in her world that didn't have a future.","TWN":"在那個本該沒有未來的世界裡，一個孩子誕生了。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 어머니로서 자신의 아이가 더 성장하길 원했어.","JPN":"パブリンは母として、自分の子どもの成長を願った。","ENG":"As a mother, Pavlin wanted her child to grow.","TWN":"作為一位母親，她希望自己的孩子能夠長大。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그 아이에게 이름을 지어주고, 미래를 계속 함께 하고 싶었어.","JPN":"子どもに名前をつけ、未来を共に生きていきたかった。","ENG":"She wanted to give her a name and have a future together.","TWN":"她想給那個孩子取個名字，並且希望能一直陪伴她走到未來。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"어느 세계에도 속하지 못한, 태어날 운명조차 없던 아이가… 그녀에겐 세상의 전부이자 무엇보다 소중한 보물이었을 거야.","JPN":"どの世界にも属してない、生まれることを許されなかった子が……彼女にとって世界のすべてであり、何よりも大切な存在だったはず。","ENG":"Because her child, the one who didn't belong to any world with no fate of ever being born... was her everything, and her most precious treasure of all.","TWN":"因為那個不屬於任何世界，甚至不該出生的孩子……對她來說，是她的全部，是比任何東西都珍貴的瑰寶。"},"stage":{"bg":"COUNTERSIDE_GARDEN","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"하지만 영원한 기다림과 달리… 그 행복은 영원하지 못하다는 걸, 파블린도 모르진 않았어.","JPN":"でも、永遠に待つことはできても……幸せは永遠に続かないことを、パブリンは知っていた。","ENG":"But... she knew that the happiness couldn't last forever, unlike the eternal wait.","TWN":"但是與永恆的等待不同……帕芙琳也知道，那份幸福並不是永恆的。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"가능성이란 건 변화와 함께 소실되기 마련이니까.","JPN":"可能性は変化に伴って失われるものだからね。","ENG":"Because possibilities are bound to be lost along with change.","TWN":"可能性總是會隨著變化而消耗殆盡。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"시간이 흐름은 두 사람에게 내일이라는 기적을 주는 동시에, 그 세계의 가능성을 서서히 집어 삼켜가고 있었어.","JPN":"時間の流れは2人に明日という奇跡を与え、同時にその世界の可能性を少しずつ蝕んでいった。","ENG":"The flow of time gave the two a miracle called tomorrow, while simultaneously slowly consuming all of the world's possibilities.","TWN":"時間的流逝不僅給兩人帶來了明天的奇蹟，同時也逐漸吞噬了那個世界的可能性。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"그러다가 결국 한계에 다다른 거야.","JPN":"そして最後に、限界が訪れたんだ。","ENG":"Then, it reached its limit.","TWN":"然後最終在某一天達到了極限。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"가능성을 잃어버린 세계에 침식이 스며들기 시작하고, 침식체들이 나타난 거지.","JPN":"可能性を失った世界は侵食され、侵食体が現れ始めた。","ENG":"Corruption began to seep into the world that lost possibilities, and with it, C.O.s started to appear.","TWN":"在失去可能性的世界中，侵蝕滲透進來，侵蝕體也出現了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOM_NPC_BIRDCAGE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리의 말이 사실이라면, 어머니는 평생의 안전을 포기하면서 절 키웠다는 건가요?","JPN":"パリーの話が本当なら、お母さんは一生の安全を手放して私を育てたってことですか？","ENG":"If what you say is true, Parry, are you saying that Mother gave up her eternal safety to raise me?","TWN":"如果悖悖的話是真的，那媽媽就是放棄了一生的安全來撫養我嗎？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런 건 이해할 수 없어요! 어째서…!","JPN":"そんなの理解できません！　どうして……！","ENG":"I don't understand! Why...?!","TWN":"我不能理解！為什麼……！"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 될 줄 알고 있었으면서… 어머니는 왜 그런 선택을…","JPN":"こうなると分かっていて……どうしてお母さんはそんな選択を……","ENG":"She knew this would happen... but why did Mother choose to–","TWN":"明明知道會變成這樣……媽媽為什麼會做出那樣的選擇……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"I'm not sure.","TWN":"這個嘛。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"내가 긴 세월을 살며 배운 것 중 하나는…","JPN":"私が長い時間生きてきて学んだことは……","ENG":"From what I've learned living all these years is...","TWN":"我在漫長歲月中學到的一件事是……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"제아무리 현명한 사람도 항상 실리를 따르는 결정만 내리진 않는단 거야.","JPN":"いくら賢い人でも、常に損得で物事を判断することはできないってことだよ。","ENG":"that no matter how wise someone is, they don't always base their decision on practicality.","TWN":"再怎麼聰明的人，也不會總是做出符合實際利益的決定。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"파블린은 단지… 자신의 아이에게 아름다운 세상을 보여주고 싶었던 거라고…","JPN":"パブリンはただ……自分の子どもに美しい世界を見せたかったんだと……","ENG":"Pavlin just... wanted to show her child a beautiful world...","TWN":"帕芙琳她……只是想讓自己的孩子看一看這個美麗的世界吧……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"적어도 난 그렇게 생각해.","JPN":"少なくとも私はそう思ってる。","ENG":"Or at least that's what I think.","TWN":"至少我是這麼認為的。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"어머니는 관리국의 영웅들이 세상을 구해줄 거래요.","JPN":"お母さんは、管理局の英雄たちが世界を救ってくれると言ってました。","ENG":"Mother said that the heroes of the Administration will save the world.","TWN":"媽媽說管理局的英雄們會拯救世界。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"세상을 구한다는 게 어떤 의미인지, 그땐 잘 몰랐어요.","JPN":"世界を救うというのがどういう意味なのか、当時はよくわかりませんでした。","ENG":"I didn't know what saving the world meant at the time.","TWN":"當時的我還不明白拯救的意思。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"제가 살아온 세상엔… 관리국도, 영웅도… 그저 머나먼 별처럼 아득한 이야기였거든요.","JPN":"私が生きてきた世界では……管理局も、英雄も……空の星のように遠いものだったんです。","ENG":"In the world I lived in... the Administration, the heroes... they all seemed like stories as distant as the stars.","TWN":"在我生活的世界裡……沒有管理局，也沒有那些英雄……他們都只是遙遠的故事而已。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그런데… 이제 조금은 알게 된 것 같아요.","JPN":"でも……これで少しはわかった気がします。","ENG":"But... I think I understand a little bit now.","TWN":"但是……現在我好像有點懂了。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"세상을 잃는다는 건… 이런 기분이겠구나… 라고…","JPN":"世界を失うと……こんな気持ちなんだろうな……って。","ENG":"Of what it feels... to lose one's world...","TWN":"失去一個人的世界……大概就是這種感覺吧……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"패리가 온 곳에선 지금도… 사람들이 세상을 잃지 않기 위해 싸우고 있는 거죠?","JPN":"パリーが元いた世界では今も……人々が、自分の世界を守るために戦っているんですよね？","ENG":"Where you're from... people are still fighting to not lose their world, right?","TWN":"在悖悖來的地方，人們也在為了留住他們的世界而戰鬥吧？"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Yes.","TWN":"……是的。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"다들 세계를 지킨다는 대단한 포부를 갖고 있는 건 아니지만… 하루 하루 최선을 다하고 있어.","JPN":"全員が、世界を守るという大それた使命で動いているわけじゃないけど……毎日一生懸命戦っている。","ENG":"Though not everyone has great aspirations to protect the world... they all do their best every day.","TWN":"雖然不是所有人都有守護世界這種偉大抱負……但大家都做得很棒。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"때론 성가시게 고된 날도 있고, 위기 앞에 좌절하게 되는 때도 있지만…","JPN":"辛い日もあるし、危機に直面して挫折する日もあるけど……","ENG":"At times, there are annoyingly difficult days, and in others, we might get frustrated in the face of a crisis, but...","TWN":"有時會有煩人日子，也有在危機面前感到沮喪的時候……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"다들 저마다의 작은 세상을 지키려고, 열심히 발버둥 치고 있어.","JPN":"それぞれの小さな世界を守るために足掻いているの。","ENG":"Each person works hard to protect their own little worlds.","TWN":"每個人都在努力地，守護著自己的小世界。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"그럼 저도…","JPN":"じゃあ、私も……","ENG":"Then I...","TWN":"那我也……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"발버둥 쳐볼게요.","JPN":"足掻いてみます。","ENG":"I will also work hard to do so.","TWN":"會加油的。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"미래를 위한 사람들의 노력이 헛되지 않았으면 좋겠으니까요.","JPN":"未来のための、皆の努力が報われてほしいから。","ENG":"Because I don't want their efforts for a better future to be in vain.","TWN":"我不想……大家為未來所付出的努力白費。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"돌아가서 준비해요.","JPN":"帰って、準備しましょう。","ENG":"Let's go back and get ready.","TWN":"我們回去吧。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLOVEY_ADMIN_NULL_NULL","text":{"KOREA":"보물을 되찾아야죠.","JPN":"お宝を取り戻さないと。","ENG":"We have to get the treasure back.","TWN":"還要去找寶物呢。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"…그래.","JPN":"……そうだね。","ENG":"...Sure.","TWN":"……是啊。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"가자.","JPN":"行こう。","ENG":"Let's go.","TWN":"我們走吧。"},"stage":{"bg":"SWORDGRAVE_STAR","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLOVEY_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};